import { createSlice } from '@reduxjs/toolkit';


let initialState = {
	sidebar:{
		department:false,
		category:false,
		menswear:{
			top:false,
			bottoms:false,
			outerwear:false,
			footwear:false,
			tailoring:false,
			accessories:false,

		},
		womenswear:{
			top:false,
			bottoms:false,
			outerwear:false,
			footwear:false,
			dresses:false,
			accessories:false,
			bagsAndLugguage:false
		},
		size:false,
		designer:false,
		price:false,
		condition:false
	},
	listing:{
		listing:[]
	}
}

const shopSlice = createSlice({
	name:'shop',
	initialState,
	reducers:{
		openDepartment:state => {
			state.sidebar.department = !state.sidebar.department
		},
		openCategory:state => {
			state.sidebar.category = !state.sidebar.category
		},
		openMenswearTop:state => {
			state.sidebar.menswear.top = !state.sidebar.menswear.top
		},
		openMenswearBottoms:state => {
			state.sidebar.menswear.bottoms = !state.sidebar.menswear.bottoms
		},
		openMenswearOuterwear:state => {
			state.sidebar.menswear.outerwear = !state.sidebar.menswear.outerwear
		},
		openMenswearFootwear:state => {
			state.sidebar.menswear.footwear = !state.sidebar.menswear.footwear
		},
		openMenswearTailoring:state => {
			state.sidebar.menswear.tailoring = !state.sidebar.menswear.tailoring
		},
		openMenswearAccessories:state => {
			state.sidebar.menswear.accessories = !state.sidebar.menswear.accessories
		},
		openWomenswearTop:state => {
			state.sidebar.womenswear.top = !state.sidebar.womenswear.top
		},
		openWomenswearBottoms:state => {
			state.sidebar.womenswear.bottoms = !state.sidebar.womenswear.bottoms
		},
		openWomenswearOuterwear:state => {
			state.sidebar.womenswear.outerwear = !state.sidebar.womenswear.outerwear
		},
		openWomenswearFootwear:state => {
			state.sidebar.womenswear.footwear = !state.sidebar.womenswear.footwear
		},
		openWomenswearDresses:state => {
			state.sidebar.womenswear.dresses = !state.sidebar.womenswear.dresses
		},
		openWomenswearAccessories:state => {
			state.sidebar.womenswear.accessories = !state.sidebar.womenswear.accessories
		},
		openWomenswearBagsAndLugguage:state => {
			state.sidebar.womenswear.bagsAndLugguage = !state.sidebar.womenswear.bagsAndLugguage
		},
		openSize:state => {
			state.sidebar.size = !state.sidebar.size
		},
		openDesigner:state => {
			state.sidebar.designer = !state.sidebar.designer
		},
		openPrice:state => {
			state.sidebar.price = !state.sidebar.price
		},
		openCondition:state => {
			state.sidebar.condition = !state.sidebar.condition
		},
		getListing:(state, action) => {
			state.listing.listing = action.payload
		}

	}
})

export const {
	openDepartment,
	openCategory,
	openMenswearTop,
	openMenswearBottoms,
	openMenswearOuterwear,
	openMenswearFootwear,
	openMenswearTailoring,
	openMenswearAccessories,
	openWomenswearTop,
	openWomenswearBottoms,
	openWomenswearOuterwear,
	openWomenswearFootwear,
	openWomenswearDresses,
	openWomenswearAccessories,
	openWomenswearBagsAndLugguage,
	openSize,
	openDesigner,
	openPrice,
	openCondition
} = shopSlice.actions
export const shopSelector = state => state.shop
export default shopSlice.reducer
